"use client";

import { useState, useEffect } from "react";
import { 
  Brain, 
  Zap, 
  ShieldAlert, 
  TrendingUp, 
  MousePointerClick, 
  Clock, 
  Globe, 
  Lock, 
  ShoppingCart, 
  UserX,
  AlertTriangle,
  CheckCircle2,
  BarChart3,
  Dna,
  Terminal,
  Play,
  History,
  Info,
  ShieldCheck,
  Cpu
} from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { toast } from "sonner";
import FullPageLoader from "@/components/FullPageLoader";

// --- Types ---
interface ModelMetric {
  accuracy: number;
  precision: number;
  recall: number;
  f1: number;
  trainTime: number;
  inferenceTime: number;
}

interface AttackScenario {
  id: string;
  name: string;
  description: string;
  icon: any;
  severity: "low" | "medium" | "high" | "critical";
  features: {
    time_to_checkout: number;
    failed_logins: number;
    ip_distance: number;
    pages_viewed: number;
    amount: number;
    device_changed: boolean;
    hour_of_day: number;
  };
}

// --- Data ---
const SCENARIOS: AttackScenario[] = [
  {
    id: "bot_auto",
    name: "Automated Bot (Speed)",
    description: "Tß║Ñn c├┤ng bß║▒ng bot vß╗¢i tß╗æc ─æß╗Ö thanh to├ín si├¬u nhanh ngay sau khi v├áo trang.",
    icon: Zap,
    severity: "high",
    features: { time_to_checkout: 1.5, failed_logins: 0, ip_distance: 10, pages_viewed: 1, amount: 250000, device_changed: false, hour_of_day: 14 }
  },
  {
    id: "brute_force",
    name: "Credential Brute Force",
    description: "T├ái khoß║ún ─æ─âng nhß║¡p sai nhiß╗üu lß║ºn tr╞░ß╗¢c khi th├ánh c├┤ng (Dß║Ñu hiß╗çu d├▓ mß║¡t khß║⌐u).",
    icon: Lock,
    severity: "critical",
    features: { time_to_checkout: 120, failed_logins: 15, ip_distance: 150, pages_viewed: 5, amount: 150000, device_changed: true, hour_of_day: 3 }
  },
  {
    id: "location_spoof",
    name: "Impossible Travel",
    description: "─É─âng nhß║¡p tß╗½ vß╗ï tr├¡ ─æß╗ïa l├╜ c├ích xa h├áng ngh├¼n km chß╗ë trong thß╗¥i gian ngß║»n.",
    icon: Globe,
    severity: "high",
    features: { time_to_checkout: 300, failed_logins: 0, ip_distance: 5400, pages_viewed: 12, amount: 900000, device_changed: true, hour_of_day: 10 }
  },
  {
    id: "whale_sniper",
    name: "High-Value Sniping",
    description: "V├áo trang web v├á chß║íy ngay ─æß║┐n sß║ún phß║⌐m ─æß║»t nhß║Ñt ─æß╗â mua m├á kh├┤ng xem g├¼ kh├íc.",
    icon: TrendingUp,
    severity: "medium",
    features: { time_to_checkout: 15, failed_logins: 0, ip_distance: 5, pages_viewed: 2, amount: 45000000, device_changed: false, hour_of_day: 22 }
  },
  {
    id: "velocity_attack",
    name: "Velocity Spamming",
    description: "Gß╗¡i h├áng loß║ít y├¬u cß║ºu mua h├áng gi├í trß╗ï thß║Ñp trong thß╗¥i gian cß╗▒c ngß║»n.",
    icon: MousePointerClick,
    severity: "medium",
    features: { time_to_checkout: 4, failed_logins: 0, ip_distance: 2, pages_viewed: 4, amount: 10000, device_changed: false, hour_of_day: 1 }
  },
  {
    id: "account_takeover",
    name: "Full Account Takeover",
    description: "Kß║┐t hß╗úp thiß║┐t bß╗ï mß╗¢i, IP lß║í, ─æß╗òi ─æß╗ïa chß╗ë v├á mua m├│n ─æß╗ô ─æß║»t ─æß╗Å.",
    icon: UserX,
    severity: "critical",
    features: { time_to_checkout: 45, failed_logins: 1, ip_distance: 1200, pages_viewed: 3, amount: 12000000, device_changed: true, hour_of_day: 4 }
  }
];

export default function AISecurityPage() {
  const [activeTab, setActiveTab] = useState<"dashboard" | "simulator" | "monitor">("dashboard");
  const [loading, setLoading] = useState(true);
  const [selectedScenario, setSelectedScenario] = useState<AttackScenario | null>(null);
  const [simResult, setSimResult] = useState<any>(null);

  useEffect(() => {
    const timer = setTimeout(() => setLoading(false), 800);
    return () => clearTimeout(timer);
  }, []);

  // Mock Performance Data
  const metrics = {
    rf: { accuracy: 96.5, precision: 94.2, recall: 92.8, f1: 93.5, trainTime: 4.2, inferenceTime: 0.012 },
    svm: { accuracy: 92.1, precision: 89.5, recall: 88.2, f1: 88.8, trainTime: 12.8, inferenceTime: 0.085 }
  };

  const handleRunSimulation = async (scenario: AttackScenario) => {
    setSelectedScenario(scenario);
    // Note: this internal simulation loading is separate from the full page loader
    setSimResult(null);
    const startSimLoading = true;
    
    // Simulate API Call to ML Engine
    setTimeout(() => {
      // Logic giß║ú ─æß╗ïnh kß║┐t quß║ú so s├ính
      const rf_risk = scenario.severity === "critical" ? 0.98 : (scenario.severity === "high" ? 0.85 : 0.65);
      const svm_risk = rf_risk - 0.05 - (Math.random() * 0.1); // Giß║ú ─æß╗ïnh SVM k├⌐m h╞ín ch├║t trong b├ái to├ín n├áy
      
      setSimResult({
        rf: { risk: rf_risk, status: rf_risk > 0.8 ? "Fraud" : "Suspicious", time: "12ms" },
        svm: { risk: svm_risk, status: svm_risk > 0.8 ? "Fraud" : "Suspicious", time: "85ms" }
      });
      
      if (rf_risk > 0.9) {
        toast.error("Hß╗ç thß╗æng tß╗▒ ─æß╗Öng: ─É├ú tß║ím kh├│a t├ái khoß║ún do rß╗ºi ro Critical!");
      } else {
        toast.warning("Cß║únh b├ío: Ph├ít hiß╗çn h├ánh vi nghi vß║Ñn. ─É├ú gß╗¡i y├¬u cß║ºu x├íc thß╗▒c 2 lß╗¢p.");
      }
    }, 1500);
  };

  return (
    <div className="bg-background min-h-screen">
      <AnimatePresence>
        {loading && <FullPageLoader key="loader" />}
      </AnimatePresence>

      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: loading ? 0 : 1 }}
        transition={{ duration: 0.5 }}
        className="p-6 md:p-8 max-w-7xl mx-auto space-y-8"
      >
        {/* Header */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 pb-2">
          <div className="space-y-2">
            <div className="flex items-center gap-3">
               <div className="p-2 bg-primary/10 rounded-xl">
                 <Brain className="text-primary" size={28} />
               </div>
               <h1 className="text-3xl font-bold tracking-tight">AI Fraud Research</h1>
            </div>
            <p className="text-muted-foreground">Nghi├¬n cß╗⌐u so s├ính Random Forest & SVM trong ph├ít hiß╗çn gian lß║¡n h├ánh vi.</p>
          </div>
          
          <div className="flex bg-muted p-1 rounded-xl">
            <button 
              onClick={() => setActiveTab("dashboard")}
              className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'dashboard' ? 'bg-background shadow-sm text-primary' : 'text-muted-foreground hover:text-foreground'}`}
            >
              <BarChart3 size={16} className="inline mr-2" /> Dashboard
            </button>
            <button 
              onClick={() => setActiveTab("simulator")}
              className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'simulator' ? 'bg-background shadow-sm text-primary' : 'text-muted-foreground hover:text-foreground'}`}
            >
              <Terminal size={16} className="inline mr-2" /> Simulator
            </button>
            <button 
              onClick={() => setActiveTab("monitor")}
              className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'monitor' ? 'bg-background shadow-sm text-primary' : 'text-muted-foreground hover:text-foreground'}`}
            >
              <ShieldAlert size={16} className="inline mr-2" /> Monitor
            </button>
          </div>
        </div>

      <AnimatePresence mode="wait">
        {/* --- TAB 1: DASHBOARD --- */}
        {activeTab === "dashboard" && (
          <motion.div 
            key="dashboard" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }}
            className="grid grid-cols-1 lg:grid-cols-3 gap-6"
          >
            <div className="lg:col-span-2 space-y-6">
              <div className="bg-card border border-border rounded-2xl p-6 shadow-sm">
                <h2 className="text-lg font-bold mb-6 flex items-center gap-2">
                  <Dna className="text-primary" size={20} /> Comparative Performance Metrics
                </h2>
                <div className="space-y-8">
                  {/* Accuracy Comparison */}
                  <div className="space-y-3">
                    <div className="flex justify-between text-sm">
                      <span className="font-medium">Model Accuracy (%)</span>
                    </div>
                    <div className="space-y-4">
                      <div className="space-y-1">
                        <div className="flex justify-between text-[10px] font-bold uppercase opacity-60"><span>Random Forest</span><span>{metrics.rf.accuracy}%</span></div>
                        <div className="h-3 bg-muted rounded-full overflow-hidden">
                          <motion.div initial={{ width: 0 }} animate={{ width: `${metrics.rf.accuracy}%` }} className="h-full bg-primary" transition={{ duration: 1 }} />
                        </div>
                      </div>
                      <div className="space-y-1">
                        <div className="flex justify-between text-[10px] font-bold uppercase opacity-60"><span>SVM (RBF Kernel)</span><span>{metrics.svm.accuracy}%</span></div>
                        <div className="h-3 bg-muted rounded-full overflow-hidden">
                          <motion.div initial={{ width: 0 }} animate={{ width: `${metrics.svm.accuracy}%` }} className="h-full bg-indigo-500" transition={{ duration: 1, delay: 0.2 }} />
                        </div>
                      </div>
                    </div>
                  </div>

                  {/* Other Metrics Bar */}
                  <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 pt-4 border-t border-border/50">
                    <MetricBox label="Precision" rf={metrics.rf.precision} svm={metrics.svm.precision} />
                    <MetricBox label="Recall" rf={metrics.rf.recall} svm={metrics.svm.recall} />
                    <MetricBox label="F1-Score" rf={metrics.rf.f1} svm={metrics.svm.f1} />
                    <MetricBox label="Reliability" rf={98} svm={85} />
                  </div>
                </div>
              </div>

              {/* Training Time Analysis */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="bg-card border border-border rounded-2xl p-6 shadow-sm">
                  <h3 className="text-sm font-bold mb-4 opacity-70 uppercase tracking-widest flex items-center gap-2">
                    <Clock size={16} /> Training Speed
                  </h3>
                  <div className="flex items-end gap-3 h-32">
                    <div className="flex-1 flex flex-col items-center gap-2">
                      <motion.div initial={{ height: 0 }} animate={{ height: '30%' }} className="w-full bg-primary/40 rounded-t-lg" />
                      <span className="text-[10px] font-bold">RF: {metrics.rf.trainTime}s</span>
                    </div>
                    <div className="flex-1 flex flex-col items-center gap-2">
                      <motion.div initial={{ height: 0 }} animate={{ height: '100%' }} className="w-full bg-indigo-500/40 rounded-t-lg" />
                      <span className="text-[10px] font-bold">SVM: {metrics.svm.trainTime}s</span>
                    </div>
                  </div>
                </div>
                <div className="bg-card border border-border rounded-2xl p-6 shadow-sm">
                  <h3 className="text-sm font-bold mb-4 opacity-70 uppercase tracking-widest flex items-center gap-2">
                    <Cpu size={16} /> Inference Latency
                  </h3>
                  <div className="flex items-end gap-3 h-32">
                    <div className="flex-1 flex flex-col items-center gap-2">
                      <motion.div initial={{ height: 0 }} animate={{ height: '15%' }} className="w-full bg-primary/40 rounded-t-lg" />
                      <span className="text-[10px] font-bold">RF: {metrics.rf.inferenceTime}s</span>
                    </div>
                    <div className="flex-1 flex flex-col items-center gap-2">
                      <motion.div initial={{ height: 0 }} animate={{ height: '60%' }} className="w-full bg-indigo-500/40 rounded-t-lg" />
                      <span className="text-[10px] font-bold">SVM: {metrics.svm.inferenceTime}s</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>

            {/* Sidebar info */}
            <div className="space-y-6">
               <div className="bg-primary/5 border border-primary/10 rounded-2xl p-6">
                  <h3 className="font-bold flex items-center gap-2 mb-4"><Info size={18} /> Research Insights</h3>
                  <ul className="space-y-4 text-sm leading-relaxed">
                    <li className="flex gap-3">
                      <div className="w-5 h-5 rounded-full bg-primary/20 shrink-0 flex items-center justify-center text-[10px] font-bold text-primary">1</div>
                      <p><span className="font-bold">Random Forest</span> chß╗⌐ng tß╗Å khß║ú n─âng xß╗¡ l├╜ dß╗» liß╗çu h├ánh vi phi tuyß║┐n t├¡nh (non-linear) tß╗æt h╞ín v├á tß╗æc ─æß╗Ö dß╗▒ ─æo├ín v╞░ß╗út trß╗Öi cho Real-time.</p>
                    </li>
                    <li className="flex gap-3">
                      <div className="w-5 h-5 rounded-full bg-indigo-500/20 shrink-0 flex items-center justify-center text-[10px] font-bold text-indigo-500">2</div>
                      <p><span className="font-bold">SVM</span> cß╗▒c kß╗│ nhß║íy cß║úm vß╗¢i viß╗çc chuß║⌐n h├│a (Scaling). Nß║┐u dß╗» liß╗çu kh├┤ng ─æ╞░ß╗úc chuß║⌐n h├│a tß╗æt, hiß╗çu n─âng SVM sß║╜ giß║úm s├óu.</p>
                    </li>
                    <li className="flex gap-3">
                      <div className="w-5 h-5 rounded-full bg-emerald-500/20 shrink-0 flex items-center justify-center text-[10px] font-bold text-emerald-500">3</div>
                      <p>Kß╗╣ thuß║¡t <span className="font-bold">SMOTE</span> l├á bß║»t buß╗Öc ─æß╗â m├┤ phß╗Ång sß╗▒ tinh vi cß╗ºa tß╗Öi phß║ím trong m├┤i tr╞░ß╗¥ng dataset mß║Ñt c├ón bß║▒ng lß╗¢p.</p>
                    </li>
                  </ul>
               </div>
               <div className="bg-card border border-border rounded-2xl p-6 text-center space-y-4">
                  <ShieldCheck size={48} className="mx-auto text-emerald-500 opacity-50" />
                  <h3 className="font-bold">Cybersecurity Importance</h3>
                  <p className="text-xs text-muted-foreground">Ph├ít hiß╗çn gian lß║¡n h├ánh vi kh├┤ng chß╗ë l├á bß║úo vß╗ç tiß╗ün bß║íc, m├á l├á bß║úo vß╗ç l├▓ng tin cß╗ºa kh├ích h├áng v├áo hß╗ç thß╗æng sß╗æ h├│a.</p>
               </div>
            </div>
          </motion.div>
        )}

        {/* --- TAB 2: ATTACK SIMULATOR --- */}
        {activeTab === "simulator" && (
          <motion.div 
            key="simulator" initial={{ opacity: 0, x:-20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: 20 }}
            className="grid grid-cols-1 lg:grid-cols-3 gap-8"
          >
            {/* Scenarios List */}
            <div className="lg:col-span-1 space-y-4">
              <h2 className="text-lg font-bold mb-4 flex items-center gap-2"><Play size={20} className="text-primary" /> Chß╗ìn Kß╗ïch bß║ún Tß║Ñn c├┤ng</h2>
              {SCENARIOS.map((s) => (
                <button 
                  key={s.id} 
                  onClick={() => handleRunSimulation(s)}
                  className={`w-full text-left p-4 rounded-2xl border transition-all flex gap-4 group ${selectedScenario?.id === s.id ? 'bg-primary/5 border-primary' : 'bg-card border-border hover:border-primary/50'}`}
                >
                  <div className={`p-3 rounded-xl shrink-0 group-hover:scale-110 transition-transform ${selectedScenario?.id === s.id ? 'bg-primary text-white' : 'bg-muted text-muted-foreground'}`}>
                    <s.icon size={24} />
                  </div>
                  <div className="min-w-0">
                    <h3 className="font-bold text-sm mb-1">{s.name}</h3>
                    <p className="text-xs text-muted-foreground line-clamp-2 leading-relaxed">{s.description}</p>
                    <div className="mt-2 flex items-center gap-2">
                       <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-widest ${
                         s.severity === 'critical' ? 'bg-red-500 text-white' : 
                         s.severity === 'high' ? 'bg-orange-500 text-white' : 
                         'bg-yellow-500 text-white'
                       }`}>{s.severity}</span>
                    </div>
                  </div>
                </button>
              ))}
            </div>

            {/* Simulation Results */}
            <div className="lg:col-span-2">
               <div className="bg-zinc-900 rounded-3xl p-8 text-white min-h-[500px] flex flex-col shadow-2xl relative overflow-hidden">
                  <div className="absolute top-0 right-0 w-64 h-64 bg-primary/10 blur-[100px] rounded-full -translate-y-1/2 translate-x-1/2"></div>
                  
                  <div className="relative z-10 flex items-center justify-between border-b border-white/10 pb-6 mb-8">
                     <div>
                        <p className="text-xs font-bold text-primary uppercase tracking-[0.2em] mb-1">Live Simulator</p>
                        <h2 className="text-2xl font-black">AI Fraud Engine Analysis</h2>
                     </div>
                     <Terminal className="text-primary opacity-50" size={32} />
                  </div>

                  {loading ? (
                    <div className="flex-1 flex flex-col items-center justify-center space-y-6">
                      <div className="relative">
                        <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 2, ease: "linear" }} className="w-20 h-20 border-4 border-primary/20 border-t-primary rounded-full" />
                        <Brain className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-primary" size={32} />
                      </div>
                      <div className="text-center">
                         <p className="font-mono text-sm opacity-60">Extracting behavioral features...</p>
                         <p className="font-mono text-sm text-primary animate-pulse mt-1">Comparing RF & SVM models...</p>
                      </div>
                    </div>
                  ) : simResult ? (
                    <div className="flex-1 space-y-8 animate-in fade-in duration-500">
                      {/* Scenario Summary */}
                      <div className="bg-white/5 border border-white/10 rounded-2xl p-4 flex gap-6 items-center">
                         <div className="space-y-1">
                            <p className="text-[10px] uppercase font-bold text-white/40">Target Activity</p>
                            <p className="font-bold text-primary">{selectedScenario?.name}</p>
                         </div>
                         <div className="w-px h-8 bg-white/10" />
                         <div className="space-y-1">
                            <p className="text-[10px] uppercase font-bold text-white/40">Checkout Time</p>
                            <p className="font-bold">{selectedScenario?.features.time_to_checkout}s</p>
                         </div>
                         <div className="w-px h-8 bg-white/10" />
                         <div className="space-y-1">
                            <p className="text-[10px] uppercase font-bold text-white/40">Failed Logins</p>
                            <p className="font-bold">{selectedScenario?.features.failed_logins}</p>
                         </div>
                      </div>

                      {/* Main Comparison results */}
                      <div className="grid md:grid-cols-2 gap-6">
                        {/* RF Result */}
                        <motion.div initial={{ x: -20, opacity: 0 }} animate={{ x: 0, opacity: 1 }} className="bg-white/5 border border-primary/30 rounded-3xl p-6 space-y-4">
                           <div className="flex justify-between items-center">
                              <span className="text-xs font-bold uppercase tracking-widest text-primary">Random Forest</span>
                              <span className="text-[10px] opacity-50">{simResult.rf.time}</span>
                           </div>
                           <div className="py-2">
                              <p className="text-4xl font-black">{Math.round(simResult.rf.risk * 100)}%</p>
                              <p className="text-xs font-bold uppercase tracking-widest opacity-60">Fraud Probability</p>
                           </div>
                           <div className={`px-4 py-2 rounded-xl text-xs font-black uppercase text-center ${simResult.rf.status === 'Fraud' ? 'bg-red-500 text-white' : 'bg-yellow-500 text-black'}`}>
                              {simResult.rf.status} detected
                           </div>
                        </motion.div>

                        {/* SVM Result */}
                        <motion.div initial={{ x: 20, opacity: 0 }} animate={{ x: 0, opacity: 1 }} transition={{ delay: 0.1 }} className="bg-white/5 border border-indigo-500/30 rounded-3xl p-6 space-y-4">
                           <div className="flex justify-between items-center">
                              <span className="text-xs font-bold uppercase tracking-widest text-indigo-400">SVM Classifier</span>
                              <span className="text-[10px] opacity-50">{simResult.svm.time}</span>
                           </div>
                           <div className="py-2">
                              <p className="text-4xl font-black">{Math.round(simResult.svm.risk * 100)}%</p>
                              <p className="text-xs font-bold uppercase tracking-widest opacity-60">Fraud Probability</p>
                           </div>
                           <div className={`px-4 py-2 rounded-xl text-xs font-black uppercase text-center ${simResult.svm.status === 'Fraud' ? 'bg-red-500 text-white' : 'bg-yellow-500 text-black'}`}>
                              {simResult.svm.status} detected
                           </div>
                        </motion.div>
                      </div>

                      <div className="bg-emerald-500/10 border border-emerald-500/20 rounded-2xl p-4 flex gap-3 text-sm">
                         <ShieldAlert className="text-emerald-500 shrink-0" size={20} />
                         <p className="text-emerald-100"><span className="font-bold">Hß╗ç thß╗æng ghi ch├║:</span> Tß╗Öi phß║ím mß║íng th╞░ß╗¥ng sß╗¡ dß╗Ñng c├íc script tß╗▒ ─æß╗Öng h├│a c├│ tham sß╗æ ngß║½u nhi├¬n nhß║╣ ─æß╗â tr├ính c├íc bß╗Ö lß╗ìc t─⌐nh. Chß╗ë c├│ Machine Learning vß╗¢i khß║ú n─âng nhß║¡n diß╗çn mß║½u h├ánh vi (Patterns) mß╗¢i c├│ thß╗â ─æß╗æi ph├│ hiß╗çu quß║ú.</p>
                      </div>
                    </div>
                  ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-center opacity-30 select-none">
                       <Play size={64} className="mb-4" />
                       <h3 className="text-xl font-bold uppercase tracking-[0.2em]">Ready to Launch</h3>
                       <p className="text-xs mt-2 font-mono">Select a scenario from the sidebar to start analysis.</p>
                    </div>
                  )}
               </div>
            </div>
          </motion.div>
        )}

        {/* --- TAB 3: SUSPECT MONITOR --- */}
        {activeTab === "monitor" && (
          <motion.div 
            key="monitor" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="space-y-6"
          >
             <div className="flex items-center justify-between">
                <h2 className="text-xl font-bold flex items-center gap-2">
                  <History className="text-primary" size={24} /> Bß║úng Tß╗òng hß╗úp H├ánh vi ─É├íng ngß╗¥
                </h2>
                <div className="flex gap-2">
                  <button className="px-4 py-2 bg-red-600 text-white text-xs font-bold rounded-xl hover:bg-red-700 transition-colors uppercase tracking-widest shadow-lg shadow-red-500/20">Auto-Action: ON</button>
                </div>
             </div>

             <div className="bg-card border border-border rounded-2xl overflow-hidden shadow-sm">
                <table className="w-full text-left text-sm border-collapse">
                  <thead className="bg-muted/50 border-b border-border">
                    <tr>
                      <th className="px-6 py-4 font-bold uppercase text-[10px] tracking-wider opacity-60">Account</th>
                      <th className="px-6 py-4 font-bold uppercase text-[10px] tracking-wider opacity-60">Last Method</th>
                      <th className="px-6 py-4 font-bold uppercase text-[10px] tracking-wider opacity-60">Suspected Activity</th>
                      <th className="px-6 py-4 font-bold uppercase text-[10px] tracking-wider opacity-60">Model Consensus</th>
                      <th className="px-6 py-4 font-bold uppercase text-[10px] tracking-wider opacity-60">Confidence</th>
                      <th className="px-6 py-4 font-bold uppercase text-[10px] tracking-wider opacity-60 text-right">Actions</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-border">
                    <SuspectRow user="anonymous_7h2" method="Direct Link" activity="Bot Sniping" consensus="92% RF / 88% SVM" severity="high" />
                    <SuspectRow user="tranvan_security_test" method="Proxy VPN" activity="Impossible Travel" consensus="85% RF / 79% SVM" severity="medium" />
                    <SuspectRow user="dark_phantom" method="Bot Script" activity="Velocity Spam" consensus="98% RF / 96% SVM" severity="critical" />
                    <SuspectRow user="user_8821" method="Brute Force" activity="Credential Stuffing" consensus="94% RF / 92% SVM" severity="critical" />
                    <SuspectRow user="shop_whale_01" method="Direct Pay" activity="Whale Hunt" consensus="75% RF / 65% SVM" severity="low" />
                  </tbody>
                </table>
             </div>
          </motion.div>
        )}
      </AnimatePresence>
      </motion.div>
    </div>
  );
}

function MetricBox({ label, rf, svm }: { label: string, rf: number, svm: number }) {
  return (
    <div className="p-4 bg-muted/40 rounded-xl space-y-3">
      <p className="text-[10px] font-bold uppercase opacity-60 tracking-wider">{label}</p>
      <div className="space-y-2">
        <div className="flex justify-between text-[10px] font-bold"><span>RF</span><span>{rf}%</span></div>
        <div className="h-1.5 bg-background rounded-full overflow-hidden">
          <div className="h-full bg-primary" style={{ width: `${rf}%` }} />
        </div>
        <div className="flex justify-between text-[10px] font-bold"><span>SVM</span><span>{svm}%</span></div>
        <div className="h-1.5 bg-background rounded-full overflow-hidden">
          <div className="h-full bg-indigo-500" style={{ width: `${svm}%` }} />
        </div>
      </div>
    </div>
  );
}

function SuspectRow({ user, method, activity, consensus, severity }: any) {
  const sevStyle = severity === 'critical' ? 'text-red-600 bg-red-100' : severity === 'high' ? 'text-orange-600 bg-orange-100' : 'text-yellow-600 bg-yellow-100';
  
  return (
    <tr className="hover:bg-muted/50 transition-colors group cursor-pointer">
       <td className="px-6 py-4 font-bold text-foreground">{user}</td>
       <td className="px-6 py-4 text-muted-foreground">{method}</td>
       <td className="px-6 py-4">
         <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-tighter ${sevStyle}`}>
           {activity}
         </span>
       </td>
       <td className="px-6 py-4 font-mono text-xs opacity-80">{consensus}</td>
       <td className="px-6 py-4">
          <div className="h-1.5 w-24 bg-muted rounded-full overflow-hidden">
             <div className="h-full bg-primary" style={{ width: consensus.split('%')[0] + '%' }} />
          </div>
       </td>
       <td className="px-6 py-4 text-right">
          <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
             <button className="px-3 py-1 bg-red-600 text-white text-[10px] font-bold rounded-lg" onClick={(e) => { e.stopPropagation(); toast.success("─É├ú kh├│a t├ái khoß║ún " + user); }}>Block</button>
             <button className="px-3 py-1 bg-muted text-foreground text-[10px] font-bold rounded-lg">Profile</button>
          </div>
       </td>
    </tr>
  );
}

"use client";

import { useEffect, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import axios from "axios";
import { Plus, Trash2, Edit2, ShieldAlert, Image as ImageIcon, Save, X, ExternalLink, Package, Search } from "lucide-react";
import { useAuthStore } from "@/store/useAuthStore";
import { useTranslation } from "react-i18next";
import { toast } from "sonner";
import FullPageLoader from "@/components/FullPageLoader";

const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000/api";

export default function AdminBannersPage() {
  const { t } = useTranslation();
  const { token } = useAuthStore();
  const [banners, setBanners] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  // Helper to get full image URL
  const getFullImageUrl = (path: string | null) => {
    if (!path) return null;
    if (path.startsWith("http") || path.startsWith("blob:") || path.startsWith("data:")) return path;
    const baseUrl = API_URL.replace("/api", "");
    return `${baseUrl}${path}`;
  };
  
  // Form State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingBanner, setEditingBanner] = useState<any>(null);
  const [formData, setFormData] = useState({
    title: "",
    subtitle: "",
    product_id: null as number | null,
    active: true,
    image: null as File | null
  });
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  
  // Product Search State
  const [productSearch, setProductSearch] = useState("");
  const [searchResults, setSearchResults] = useState<any[]>([]);
  const [isSearchingProducts, setIsSearchingProducts] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState<any>(null);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [imageWarning, setImageWarning] = useState<string | null>(null);
  const [pendingImage, setPendingImage] = useState<File | null>(null);

  const fetchBanners = async () => {
    if (!token) return;
    try {
      setLoading(true);
      const res = await axios.get(`${API_URL}/admin/banners`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setBanners(res.data);
    } catch (err) {
      console.error("Failed to load banners", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchBanners();
  }, [token]);

  // Debounce search
  useEffect(() => {
    const timer = setTimeout(() => {
      if (productSearch.trim().length >= 2) {
        searchProducts(productSearch);
      } else {
        setSearchResults([]);
      }
    }, 500);
    return () => clearTimeout(timer);
  }, [productSearch]);

  const searchProducts = async (query: string) => {
    if (!token) return;
    try {
      setIsSearchingProducts(true);
      const res = await axios.get(`${API_URL}/admin/banners/search-products?q=${query}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setSearchResults(res.data);
    } catch (err) {
      console.error("Search failed", err);
    } finally {
      setIsSearchingProducts(false);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      
      const reader = new FileReader();
      reader.onload = (event) => {
        const img = new Image();
        img.onload = () => {
          if (img.width <= img.height) {
             setPendingImage(file);
             setImageWarning(t("admin.banners.aspect_ratio_warning"));
             // Reset input value to allow re-selecting same file if canceled
             e.target.value = "";
             return;
          }
          setFormData(prev => ({ ...prev, image: file }));
          setPreviewUrl(URL.createObjectURL(file));
        };
        img.src = event.target?.result as string;
      };
      reader.readAsDataURL(file);
    }
  };

  const confirmImage = () => {
    if (pendingImage) {
      setFormData(prev => ({ ...prev, image: pendingImage }));
      setPreviewUrl(URL.createObjectURL(pendingImage));
      setPendingImage(null);
      setImageWarning(null);
    }
  };

  const cancelImage = () => {
    setPendingImage(null);
    setImageWarning(null);
  };

  const resetForm = () => {
    setFormData({
      title: "",
      subtitle: "",
      product_id: null,
      active: true,
      image: null
    });
    setPreviewUrl(null);
    setEditingBanner(null);
    setSelectedProduct(null);
    setProductSearch("");
    setSearchResults([]);
    setShowDeleteConfirm(false);
    setImageWarning(null);
    setPendingImage(null);
  };

  const handleOpenAdd = () => {
    resetForm();
    setIsModalOpen(true);
  };

  const handleOpenEdit = (banner: any) => {
    setEditingBanner(banner);
    setFormData({
      title: banner.title || "",
      subtitle: banner.subtitle || "",
      product_id: banner.product_id || null,
      active: !!banner.active,
      image: null
    });
    setPreviewUrl(banner.image_path);
    setSelectedProduct(banner.product || null);
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!token) return;

    const data = new FormData();
    data.append("title", formData.title);
    data.append("subtitle", formData.subtitle);
    if (!formData.product_id) {
       toast.warning(t("admin.banners.select_product_warning"));
       return;
    }
    data.append("product_id", formData.product_id.toString());
    data.append("active", formData.active ? "1" : "0");
    if (!formData.image && !editingBanner) {
       toast.warning(t("admin.banners.upload_image_warning"));
       return;
    }
    if (formData.image) {
      data.append("image", formData.image);
    }

    try {
      if (editingBanner) {
        // Laravel method spoofing for PUT with FormData
        data.append("_method", "PUT"); 
        await axios.post(`${API_URL}/admin/banners/${editingBanner.id}`, data, {
          headers: { 
            Authorization: `Bearer ${token}`,
            "Content-Type": "multipart/form-data"
          }
        });
      } else {
        await axios.post(`${API_URL}/admin/banners`, data, {
          headers: { 
            Authorization: `Bearer ${token}`,
            "Content-Type": "multipart/form-data"
          }
        });
      }
      setIsModalOpen(false);
      resetForm();
      fetchBanners();
      toast.success(editingBanner ? t("admin.banners.update_success") : t("admin.banners.create_success"));
    } catch (err: any) {
      console.error("Failed to save banner", err);
      const msg = err.response?.data?.message || t("admin.banners.save_error");
      const errors = err.response?.data?.errors;
      if (errors) {
        const detailMsg = Object.values(errors).flat().join("\n");
        toast.error(msg, { description: detailMsg });
      } else {
        toast.error(msg);
      }
    }
  };

  const handleDelete = async (id: number) => {
    if (!token) return;
    try {
      await axios.delete(`${API_URL}/admin/banners/${id}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      fetchBanners();
      setIsModalOpen(false);
      resetForm();
      toast.success(t("admin.banners.delete_success"));
    } catch (err) {
      console.error("Failed to delete banner", err);
      toast.error(t("admin.banners.delete_error"));
    }
  };

  const handleSelectProduct = (product: any) => {
    setSelectedProduct(product);
    setFormData({ ...formData, product_id: product.id });
    setProductSearch("");
    setSearchResults([]);
  };

  return (
    <div className="min-h-screen">
      <AnimatePresence>
        {loading && <FullPageLoader key="loader" />}
      </AnimatePresence>

      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: loading ? 0 : 1 }}
        transition={{ duration: 0.5 }}
        className="space-y-6 max-w-7xl mx-auto"
      >
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
           <h1 className="text-3xl font-bold tracking-tight">{t("admin.banners.title")}</h1>
           <p className="text-muted-foreground mt-1">{t("admin.banners.desc")}</p>
        </div>
        <button 
           onClick={handleOpenAdd}
           className="flex items-center gap-2 px-4 py-2 bg-primary text-primary-foreground rounded-xl font-bold transition-all hover:shadow-lg hover:shadow-primary/20 active:scale-95"
        >
           <Plus size={20} />
           {t("admin.banners.add")}
        </button>
      </div>

      {loading ? (
         <div className="flex h-64 items-center justify-center">
           <div className="w-8 h-8 rounded-full border-4 border-primary border-t-transparent animate-spin"></div>
         </div>
      ) : banners.length === 0 ? (
         <div className="bg-card border border-border rounded-xl p-12 text-center text-muted-foreground">
            <ImageIcon size={48} className="mx-auto mb-4 opacity-20" />
            <p>{t("admin.banners.no_banners")}</p>
         </div>
      ) : (
         <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {banners.map((banner) => (
               <div 
                 key={banner.id} 
                 onClick={() => handleOpenEdit(banner)}
                 className="bg-card border border-border rounded-2xl overflow-hidden shadow-sm hover:shadow-xl hover:scale-[1.02] transition-all duration-300 cursor-pointer relative group"
               >
                  <div className="aspect-video bg-muted relative overflow-hidden">
                     {banner.image_path ? (
                        <img src={getFullImageUrl(banner.image_path)!} alt={banner.title} className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" />
                     ) : (
                        <div className="w-full h-full flex items-center justify-center">
                           <ImageIcon className="text-muted-foreground/20" size={40} />
                        </div>
                     )}
                     
                     <div className="absolute top-2 left-2 z-10 flex gap-2">
                        {banner.active ? (
                           <span className="px-2 py-1 bg-emerald-500 text-white text-[9px] font-bold rounded-lg uppercase tracking-wider shadow-lg">
                              {t("admin.banners.status_active")}
                           </span>
                        ) : (
                           <span className="px-2 py-1 bg-black/60 backdrop-blur-md text-white text-[9px] font-bold rounded-lg uppercase tracking-wider shadow-lg">
                              {t("admin.banners.status_hidden")}
                           </span>
                        )}
                     </div>
                  </div>
                  <div className="p-4">
                     <div className="flex justify-between items-start gap-2">
                        <div className="min-w-0 flex-1">
                           <h3 className="font-bold line-clamp-1 group-hover:text-primary transition-colors">{banner.title || "Untitled"}</h3>
                           <p className="text-xs text-muted-foreground line-clamp-1">{banner.subtitle}</p>
                        </div>
                     </div>
                     {banner.product && (
                        <div className="mt-3 pt-3 border-t border-border flex items-center gap-2 text-[10px] text-primary font-bold overflow-hidden">
                           <Package size={12} />
                           <span className="truncate">{t("admin.banners.product_prefix")}{banner.product.title}</span>
                        </div>
                     )}
                     {/* Legacy link_url display removed */}
                  </div>
               </div>
            ))}
         </div>
      )}

      {/* Modal / Form */}
      {isModalOpen && (
         <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-background/80 backdrop-blur-sm animate-in fade-in duration-300">
            <div className="bg-card border border-border w-full max-w-xl rounded-2xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
               <div className="p-4 border-b border-border flex justify-between items-center bg-muted/20">
                  <h2 className="font-bold">{editingBanner ? t("admin.banners.edit") : t("admin.banners.add")}</h2>
                  <button onClick={() => setIsModalOpen(false)} className="p-1.5 hover:bg-muted rounded-full transition-colors text-muted-foreground"><X size={20} /></button>
               </div>

               <form onSubmit={handleSubmit} className="p-6 space-y-4 overflow-y-auto [scrollbar-gutter:stable]">
                  <div className="space-y-4">
                     {/* Image Preview / Upload */}
                     <div className="space-y-2">
                        <label className="text-xs font-bold uppercase tracking-wider text-muted-foreground">{t("admin.banners.image_label")}</label>
                        <div 
                          className="aspect-video rounded-xl border-2 border-dashed border-border bg-muted/30 relative flex items-center justify-center overflow-hidden cursor-pointer hover:bg-muted/50 transition-colors"
                          onClick={() => !imageWarning && document.getElementById('imageInput')?.click()}
                        >
                           {previewUrl ? (
                              <img src={getFullImageUrl(previewUrl)!} className="w-full h-full object-cover animate-in fade-in duration-500" />
                           ) : (
                               <div className="text-center p-4">
                                  <ImageIcon className="mx-auto mb-2 text-muted-foreground" size={32} />
                                  <p className="text-[10px] text-muted-foreground font-medium uppercase tracking-widest">{t("admin.banners.upload_hint")}</p>
                                  <p className="text-[10px] text-muted-foreground/60 mt-1 italic">{t("admin.banners.aspect_ratio_hint")}</p>
                               </div>
                           )}

                           {/* Image Validation Overlay */}
                           {imageWarning && (
                              <div className="absolute inset-0 z-20 bg-amber-600/95 backdrop-blur-sm p-4 flex flex-col items-center justify-center text-center animate-in zoom-in-95 duration-200">
                                 <ShieldAlert className="text-white mb-2" size={32} />
                                 <p className="text-white text-xs font-medium leading-relaxed mb-4">{imageWarning}</p>
                                 <div className="flex gap-2 w-full max-w-xs">
                                    <button 
                                      type="button" 
                                      onClick={(e) => { e.stopPropagation(); cancelImage(); }}
                                      className="flex-1 py-2 bg-white/20 hover:bg-white/30 text-white rounded-lg font-bold text-xs transition-colors"
                                    >
                                       {t("profile_page.cancel")}
                                    </button>
                                    <button 
                                      type="button" 
                                      onClick={(e) => { e.stopPropagation(); confirmImage(); }}
                                      className="flex-[2] py-2 bg-white text-amber-600 hover:bg-amber-50 rounded-lg font-bold text-xs transition-colors shadow-lg"
                                    >
                                       {t("admin.banners.continue_btn")}
                                    </button>
                                 </div>
                              </div>
                           )}
                           <input 
                             type="file" 
                             id="imageInput" 
                             className="hidden" 
                             accept="image/*" 
                             onChange={handleFileChange} 
                           />
                        </div>
                     </div>

                     <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1">
                           <label className="text-xs font-bold uppercase tracking-wider text-muted-foreground">{t("admin.banners.title_label")}</label>
                           <input 
                              type="text" 
                              value={formData.title}
                              onChange={(e) => setFormData({...formData, title: e.target.value})}
                              className="w-full px-4 py-2.5 bg-background border border-border rounded-xl focus:ring-2 focus:ring-primary outline-none transition-all"
                              placeholder={t("admin.banners.placeholder_title")}
                           />
                        </div>
                        <div className="space-y-1">
                           <label className="text-xs font-bold uppercase tracking-wider text-muted-foreground">{t("admin.banners.subtitle_label")}</label>
                           <input 
                              type="text" 
                              value={formData.subtitle}
                              onChange={(e) => setFormData({...formData, subtitle: e.target.value})}
                              className="w-full px-4 py-2.5 bg-background border border-border rounded-xl focus:ring-2 focus:ring-primary outline-none transition-all"
                              placeholder={t("admin.banners.placeholder_subtitle")}
                           />
                        </div>
                     </div>

                     <div className="space-y-1 relative">
                        <label className="text-xs font-bold uppercase tracking-wider text-muted-foreground">{t("admin.banners.product_link_label")}</label>
                        {selectedProduct ? (
                           <div className="flex items-center justify-between p-3 bg-primary/5 border border-primary/20 rounded-xl">
                              <div className="flex items-center gap-3">
                                 <div className="w-10 h-10 bg-primary/10 rounded-lg flex items-center justify-center text-primary">
                                    <Package size={20} />
                                 </div>
                                 <div className="min-w-0">
                                    <p className="text-sm font-bold truncate">{selectedProduct.title}</p>
                                    <p className="text-[10px] text-muted-foreground">ID: {selectedProduct.id}</p>
                                 </div>
                              </div>
                              <button 
                                type="button"
                                onClick={() => { setSelectedProduct(null); setFormData({...formData, product_id: null}); }}
                                className="p-1.5 hover:bg-red-500/10 text-red-500 rounded-lg transition-colors"
                              >
                                 <Trash2 size={16} />
                              </button>
                           </div>
                        ) : (
                           <div className="relative">
                              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-muted-foreground" size={16} />
                              <input 
                                 type="text" 
                                 value={productSearch}
                                 onChange={(e) => setProductSearch(e.target.value)}
                                 className="w-full pl-11 pr-4 py-2.5 bg-background border border-border rounded-xl focus:ring-2 focus:ring-primary outline-none transition-all"
                                 placeholder={t("admin.banners.search_product_placeholder")}
                              />
                           </div>
                        )}
                        
                        {/* Search Results Dropdown */}
                        {searchResults.length > 0 && !selectedProduct && (
                           <div className="absolute z-[60] left-0 right-0 top-full mt-1 bg-card border border-border rounded-xl shadow-2xl max-h-48 overflow-y-auto overflow-x-hidden animate-in fade-in slide-in-from-top-2">
                              {searchResults.map((p) => (
                                 <button 
                                   key={p.id}
                                   type="button"
                                   onClick={() => handleSelectProduct(p)}
                                   className="w-full p-3 text-left hover:bg-muted flex items-center gap-3 border-b border-border/50 last:border-0"
                                 >
                                    <div className="w-8 h-8 bg-muted rounded flex items-center justify-center text-muted-foreground">
                                       <Package size={14} />
                                    </div>
                                    <div className="min-w-0 flex-1">
                                       <p className="text-xs font-bold truncate">{p.title}</p>
                                       <p className="text-[9px] text-muted-foreground"> {p.price.toLocaleString()}─æ</p>
                                    </div>
                                 </button>
                              ))}
                           </div>
                        )}
                        
                        {isSearchingProducts && (
                           <div className="absolute right-4 top-[38px]">
                              <div className="w-4 h-4 border-2 border-primary border-t-transparent rounded-full animate-spin"></div>
                           </div>
                        )}
                     </div>

                     {/* Link URL field removed */}

                     <div className="grid grid-cols-2 gap-4">
                        <div className="flex flex-col justify-end pb-1">
                           <label className="flex items-center gap-3 cursor-pointer group">
                              <input 
                                 type="checkbox" 
                                 checked={formData.active}
                                 onChange={(e) => setFormData({...formData, active: e.target.checked})}
                                 className="w-5 h-5 rounded-md border-border text-primary focus:ring-primary/20 accent-primary"
                              />
                              <span className="text-sm font-bold text-foreground group-hover:text-primary transition-colors">{t("admin.banners.active_label")}</span>
                           </label>
                        </div>
                     </div>
                  </div>

                   <div className="pt-6 border-t border-border mt-2 min-h-[140px] flex flex-col gap-3">
                      <div className="flex gap-3">
                         <button 
                           type="button"
                           onClick={() => setIsModalOpen(false)}
                           className="flex-1 py-3 bg-muted hover:bg-muted/80 rounded-xl font-bold transition-all text-sm"
                         >
                            {t("profile_page.cancel")}
                         </button>
                         <button 
                           type="submit"
                           className="flex-1 py-3 bg-primary text-primary-foreground rounded-xl font-bold transition-all shadow-lg shadow-primary/20 hover:shadow-primary/40 active:scale-[0.98] text-sm"
                         >
                            {editingBanner ? t("seller.products_manage.update") : t("admin.banners.add")}
                         </button>
                      </div>
                      
                      {editingBanner && (
                        <div className="pt-2 border-t border-border/50 min-h-[50px]">
                           {!showDeleteConfirm ? (
                             <button 
                               type="button"
                               onClick={() => setShowDeleteConfirm(true)}
                               className="w-full py-2.5 bg-red-500/10 text-red-500 hover:bg-red-500 hover:text-white rounded-xl font-bold transition-all text-xs flex items-center justify-center gap-2"
                             >
                                <Trash2 size={14} />
                                {t("inbox.delete")} Banner
                             </button>
                           ) : (
                             <div className="flex gap-2 animate-in slide-in-from-bottom-2 duration-300">
                                <button 
                                  type="button"
                                  onClick={() => setShowDeleteConfirm(false)}
                                  className="flex-1 py-2 bg-muted rounded-xl font-bold text-xs hover:bg-muted/80 transition-colors"
                                >
                                   {t("admin.banners.back_btn")}
                                </button>
                                <button 
                                  type="button"
                                  onClick={() => handleDelete(editingBanner.id)}
                                  className="flex-[2] py-2 bg-red-600 text-white rounded-xl font-bold text-xs hover:bg-red-700 transition-colors shadow-lg shadow-red-500/20"
                                >
                                   {t("admin.banners.confirm_delete_btn")}
                                </button>
                             </div>
                           )}
                        </div>
                      )}
                   </div>
               </form>
            </div>
         </div>
      )}
      </motion.div>
    </div>
  );
}

