      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import axios from "axios";
import { Settings, Save, Percent, Truck, Power } from "lucide-react";
import { useAuthStore } from "@/store/useAuthStore";
import { useTranslation } from "react-i18next";
import FullPageLoader from "@/components/FullPageLoader";

const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000/api";

export default function AdminSettingsPage() {
  const { t } = useTranslation();
  const { token } = useAuthStore();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [message, setMessage] = useState({ type: "", text: "" });

  const [settings, setSettings] = useState({
    platform_fee: "5",
    shipping_base_rate: "10.00",
    tax_rate: "8.5",
    maintenance_mode: "0", // Stored as string '0' or '1'
  });

  const fetchSettings = async () => {
    if (!token) return;
    try {
      setLoading(true);
      const res = await axios.get(`${API_URL}/admin/settings`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      
      const data = res.data;
      // Pre-fill state with fetched keys if they exist
      setSettings(prev => ({
        platform_fee: data['platform_fee']?.value ?? prev.platform_fee,
        shipping_base_rate: data['shipping_base_rate']?.value ?? prev.shipping_base_rate,
        tax_rate: data['tax_rate']?.value ?? prev.tax_rate,
        maintenance_mode: data['maintenance_mode']?.value ?? prev.maintenance_mode,
      }));
    } catch (err) {
      console.error("Failed to load settings", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchSettings();
  }, [token]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!token) return;
    try {
      setSaving(true);
      setMessage({ type: "", text: "" });

      // Transform state object into array format requested by backend
      const payload = Object.entries(settings).map(([key, value]) => ({
         key,
         value: value.toString(),
         type: key === 'maintenance_mode' ? 'boolean' : 'numeric',
         group: key === 'platform_fee' ? 'finance' : 'platform'
      }));

      await axios.put(`${API_URL}/admin/settings`, { settings: payload }, {
        headers: { Authorization: `Bearer ${token}` }
      });

      setMessage({ type: "success", text: t("admin.system_config.update_success") });
    } catch (err) {
      setMessage({ type: "error", text: t("admin.system_config.update_error") });
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="min-h-screen">
      <AnimatePresence>
        {loading && <FullPageLoader key="loader" />}
      </AnimatePresence>

      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: loading ? 0 : 1 }}
        transition={{ duration: 0.5 }}
        className="space-y-6 max-w-4xl mx-auto"
      >
      <div>
        <h1 className="text-3xl font-bold tracking-tight">{t("admin.system_config.title")}</h1>
        <p className="text-muted-foreground mt-1">{t("admin.system_config.desc")}</p>
      </div>

      {message.text && (
        <div className={`p-4 rounded-xl text-sm font-medium ${message.type === 'success' ? 'bg-green-500/10 text-green-600' : 'bg-red-500/10 text-red-600'}`}>
          {message.text}
        </div>
      )}

      <form onSubmit={handleSubmit} className="space-y-6">
        
        {/* Core Settings */}
        <div className="bg-card border border-border rounded-xl shadow-sm overflow-hidden flex flex-col">
          <div className="px-6 py-5 border-b border-border bg-muted/20 flex items-center gap-2">
            <Settings className="text-primary" size={20} />
            <h2 className="text-lg font-bold">{t("admin.system_config.platform_params")}</h2>
          </div>
          
          <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-medium mb-1.5 text-muted-foreground flex items-center gap-2">
                <Percent size={16} /> {t("admin.system_config.platform_fee")}
              </label>
              <input 
                type="number" 
                step="0.1"
                min="0"
                value={settings.platform_fee}
                onChange={(e) => setSettings({...settings, platform_fee: e.target.value})}
                className="w-full px-4 py-2.5 bg-background border border-input rounded-xl focus:outline-none focus:ring-2 focus:ring-primary font-medium"
              />
              <p className="text-xs text-muted-foreground mt-2">{t("admin.system_config.platform_fee_desc")}</p>
            </div>

            <div>
              <label className="block text-sm font-medium mb-1.5 text-muted-foreground flex items-center gap-2">
                <Truck size={16} /> {t("admin.system_config.shipping_rate")}
              </label>
              <input 
                type="number" 
                step="0.01"
                min="0"
                value={settings.shipping_base_rate}
                onChange={(e) => setSettings({...settings, shipping_base_rate: e.target.value})}
                className="w-full px-4 py-2.5 bg-background border border-input rounded-xl focus:outline-none focus:ring-2 focus:ring-primary font-medium"
              />
              <p className="text-xs text-muted-foreground mt-2">{t("admin.system_config.shipping_rate_desc")}</p>
            </div>

            <div>
              <label className="block text-sm font-medium mb-1.5 text-muted-foreground flex items-center gap-2">
                <Percent size={16} /> {t("admin.system_config.tax_rate")}
              </label>
              <input 
                type="number" 
                step="0.01"
                min="0"
                value={settings.tax_rate}
                onChange={(e) => setSettings({...settings, tax_rate: e.target.value})}
                className="w-full px-4 py-2.5 bg-background border border-input rounded-xl focus:outline-none focus:ring-2 focus:ring-primary font-medium"
              />
              <p className="text-xs text-muted-foreground mt-2">{t("admin.system_config.tax_rate_desc")}</p>
            </div>
          </div>
        </div>

        {/* Operational Guard */}
        <div className="bg-card border border-border rounded-xl shadow-sm overflow-hidden flex flex-col">
           <div className="p-6 flex items-center justify-between">
              <div>
                 <h2 className="text-lg font-bold flex items-center gap-2">
                    <Power size={20} className={settings.maintenance_mode === "1" ? "text-amber-500" : "text-green-500"} />
                    {t("admin.system_config.maintenance_mode")}
                 </h2>
                 <p className="text-sm text-muted-foreground mt-1">{t("admin.system_config.maintenance_desc")}</p>
              </div>
              <label className="relative inline-flex items-center cursor-pointer shrinks-0">
                 <input 
                    type="checkbox" 
                    className="sr-only peer"
                    checked={settings.maintenance_mode === "1"}
                    onChange={(e) => setSettings({...settings, maintenance_mode: e.target.checked ? "1" : "0"})}
                 />
                 <div className="w-11 h-6 bg-muted peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-border after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-amber-500"></div>
              </label>
           </div>
        </div>

        <div className="flex justify-end pt-4">
           <button 
             type="submit" 
             disabled={saving}
             className="flex items-center gap-2 bg-primary text-primary-foreground px-8 py-3 rounded-xl font-bold hover:bg-primary/90 transition-colors disabled:opacity-50"
           >
              <Save size={18} />
              {saving ? t("admin.system_config.saving") : t("admin.system_config.save_all")}
           </button>
        </div>

      </form>
      </motion.div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import axios from "axios";
import { format } from "date-fns";
import { vi, enUS } from "date-fns/locale";
import { Users, Search, Filter, ShieldAlert, MoreVertical, Trash2, Eye } from "lucide-react";
import { useAuthStore } from "@/store/useAuthStore";
import { useTranslation } from "react-i18next";
import FullPageLoader from "@/components/FullPageLoader";

const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000/api";

export default function AdminUsersPage() {
  const { t } = useTranslation();
  const { token, user } = useAuthStore();
  const [users, setUsers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  
  // Filters
  const [search, setSearch] = useState("");
  const [roleFilter, setRoleFilter] = useState("all");
  
  // Pagination
  const [pagination, setPagination] = useState({
    current_page: 1,
    last_page: 1,
    total: 0
  });

  const fetchUsers = async (page = 1) => {
    if (!token) return;
    try {
      setLoading(true);
      const res = await axios.get(`${API_URL}/admin/users`, {
        headers: { Authorization: `Bearer ${token}` },
        params: {
          page,
          search: search || undefined,
          role_id: roleFilter !== "all" ? roleFilter : undefined
        }
      });
      setUsers(res.data.data);
      setPagination({
        current_page: res.data.current_page,
        last_page: res.data.last_page,
        total: res.data.total
      });
    } catch (err) {
      console.error("Failed to load users", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchUsers(1);
  }, [token, roleFilter, search]);

  const handleDeleteUser = async (id: number, name: string) => {
    if (!token) return;
    if (id === user?.id) {
       alert(t("admin.users_manage.self_delete_error"));
       return;
    }
    if (!confirm(t("admin.users_manage.confirm_delete", { name }))) {
      return;
    }

    try {
      await axios.delete(`${API_URL}/admin/users/${id}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      // Refresh list
      fetchUsers(pagination.current_page);
    } catch (err: any) {
      alert(err.response?.data?.message || "Failed to delete user");
    }
  };

  return (
    <div className="min-h-screen">
      <AnimatePresence>
        {loading && <FullPageLoader key="loader" />}
      </AnimatePresence>

      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: loading ? 0 : 1 }}
        transition={{ duration: 0.5 }}
        className="space-y-6 max-w-7xl mx-auto"
      >
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">{t("admin.users")}</h1>
          <p className="text-muted-foreground mt-1">{t("admin.users_manage.desc")}</p>
        </div>
        
        <div className="flex bg-primary/10 text-primary px-4 py-2 rounded-xl text-sm font-bold items-center gap-2">
           <Users size={16} />
           {t("admin.users_manage.total_users")}: {pagination.total}
        </div>
      </div>

      <div className="bg-card border border-border rounded-xl shadow-sm overflow-hidden flex flex-col">
        {/* Toolbar */}
        <div className="p-4 border-b border-border bg-muted/20 flex flex-col sm:flex-row gap-4 justify-between items-center whitespace-nowrap">
          <div className="relative w-full sm:w-96">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" size={18} />
            <input 
              type="text" 
              placeholder={t("admin.users_manage.search_placeholder")}
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-10 pr-4 py-2 bg-background border border-input rounded-xl focus:outline-none focus:ring-2 focus:ring-primary text-sm"
            />
          </div>

          <div className="flex items-center gap-3 w-full sm:w-auto">
             <div className="flex items-center gap-2 bg-background border border-border px-3 py-2 rounded-xl text-sm">
                <Filter size={16} className="text-muted-foreground" />
                <select 
                  value={roleFilter}
                  onChange={(e) => setRoleFilter(e.target.value)}
                  className="bg-transparent focus:outline-none min-w-[120px]"
                >
                  <option value="all">{t("admin.users_manage.all_roles")}</option>
                  <option value="1">{t("admin.users_manage.customers")}</option>
                  <option value="2">{t("admin.users_manage.sellers")}</option>
                  <option value="3">{t("admin.users_manage.admins")}</option>
                </select>
             </div>
          </div>
        </div>

        {/* Table */}
        <div className="overflow-x-auto min-h-[400px]">
          {loading ? (
            <div className="flex h-64 items-center justify-center">
              <div className="w-8 h-8 rounded-full border-4 border-primary border-t-transparent animate-spin"></div>
            </div>
          ) : users.length === 0 ? (
            <div className="p-12 text-center text-muted-foreground">
               <Users size={48} className="mx-auto mb-4 opacity-20" />
               <p>{t("admin.users_manage.no_users_found")}</p>
            </div>
          ) : (
            <table className="w-full text-sm text-left">
              <thead className="text-xs text-muted-foreground bg-muted/50 uppercase">
                <tr>
                  <th className="px-6 py-4 font-medium">{t("admin.users_manage.user_email")}</th>
                  <th className="px-6 py-4 font-medium">{t("admin.role")}</th>
                  <th className="px-6 py-4 font-medium">{t("admin.joined_date")}</th>
                  <th className="px-6 py-4 font-medium text-right">{t("admin.actions")}</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {users.map((u) => (
                  <tr key={u.id} className="hover:bg-muted/30 group">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-full bg-primary/20 text-primary flex items-center justify-center font-bold shrink-0">
                          {u.name.charAt(0).toUpperCase()}
                        </div>
                        <div>
                           <p className="font-bold">{u.name}</p>
                           <p className="text-xs text-muted-foreground">{u.email}</p>
                           {u.profile?.phone && <p className="text-xs text-muted-foreground mt-0.5">{u.profile.phone}</p>}
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex items-center px-2.5 py-1 rounded-full text-xs font-bold uppercase tracking-wider ${
                           u.role_id === 1 ? 'bg-blue-500/10 text-blue-500' :
                           u.role_id === 2 ? 'bg-purple-500/10 text-purple-500' :
                           'bg-red-500/10 text-red-500'
                         }`}>
                           {t(`roles.${u.role?.slug || 'customer'}`)}
                         </span>
                    </td>
                    <td className="px-6 py-4 text-muted-foreground whitespace-nowrap">
                       {format(new Date(u.created_at), t("locale") === "vi-VN" ? "dd/MM/yyyy" : "MMM d, yyyy", { 
                         locale: t("locale") === "vi-VN" ? vi : enUS 
                       })}
                    </td>
                    <td className="px-6 py-4 text-right">
                       <div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button 
                            className="p-2 bg-background shadow-sm border border-border rounded-lg text-muted-foreground hover:text-primary transition-colors"
                            title={t("admin.users_manage.view_details")}
                          >
                            <Eye size={16} />
                          </button>
                          
                          {u.id !== user?.id && u.role_id !== 3 && (
                            <button 
                              onClick={() => handleDeleteUser(u.id, u.name)}
                              className="p-2 bg-background shadow-sm border border-red-500/20 rounded-lg text-red-500 hover:bg-red-500 hover:text-white transition-colors"
                              title={t("admin.users_manage.delete_user")}
                            >
                              <Trash2 size={16} />
                            </button>
                          )}
                       </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>

        {/* Pagination Controls */}
        {!loading && pagination.last_page > 1 && (
          <div className="px-6 py-4 border-t border-border bg-muted/10 flex items-center justify-between">
            <span className="text-sm text-muted-foreground whitespace-nowrap">
              {t("admin.users_manage.page_of", { current: pagination.current_page, total: pagination.last_page })}
            </span>
            <div className="flex gap-1.5 overflow-x-auto no-scrollbar py-1">
              {[...Array(pagination.last_page)].map((_, i) => (
                <button 
                  key={i} 
                  onClick={() => fetchUsers(i + 1)}
                  className={`w-8 h-8 rounded-lg text-xs font-bold transition-all shrink-0 ${pagination.current_page === i + 1 ? "bg-primary text-primary-foreground shadow-md shadow-primary/20" : "bg-background border border-border hover:bg-accent"}`}
                >
                  {i + 1}
                </button>
              ))}
            </div>
          </div>
        )}
      </div>
      </motion.div>
    </div>
  );
}
